1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	const isComponent = (item: any): boolean =>
17	  COMPONENT_TYPES.includes(item.type);
18	
19	const itemBasePremium = (item: any): number =>
20	  BASE_PREMIUMS[item.type] ?? 0;
21	
22	const itemPremiumWithModifiers = (item: any): number => {
23	  const base = itemBasePremium(item);
24	  return base
25	    + (item.cursed ? base * 0.5 : 0)
26	    + (item.enchantment >= 5 ? base * 0.3 : 0);
27	};
28	
29	const regularItems = (items: any[]): any[] =>
30	  items.filter((item: any) => !isComponent(item));
31	
32	const regularItemsPremium = (items: any[]): number =>
33	  regularItems(items)
34	    .reduce((sum: number, item: any) => sum + itemPremiumWithModifiers(item), 0);
35	
36	const componentBlockPremium = (count: number, type: string): number =>
37	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
38	
39	const countComponentsByType = (items: any[]): Record<string, number> =>
40	  items.filter(isComponent).reduce(
41	    (acc: Record<string, number>, item: any) => ({
42	      ...acc,
43	      [item.type]: (acc[item.type] ?? 0) + 1,
44	    }),
45	    {},
46	  );
47	
48	const componentsPremium = (items: any[]): number =>
49	  Object.entries(countComponentsByType(items)).reduce(
50	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
51	    0,
52	  );
53	
54	const policyBasePremium = (items: any[]): number =>
55	  regularItems(items)
56	    .reduce((sum: number, item: any) => sum + itemBasePremium(item), 0)
57	  + componentsPremium(items);
58	
59	const policyWideModifierRate = (customer: any, quoteIndex: number): number =>
60	  0.1 + (customer.yearsWithMHPCO >= 2 ? -0.2 : 0) + (quoteIndex > 0 ? -0.15 : 0);
61	
62	const validateItemTypes = (items: any[]): void => {
63	  const unknownItem = items.find((item: any) => !(item.type in BASE_PREMIUMS));
64	  if (unknownItem) {
65	    throw new Error(`Unknown item type: ${unknownItem.type}`);
66	  }
67	};
68	
69	const calculateQuotePremium = (items: any[], customer: any, quoteIndex: number): number => {
70	  validateItemTypes(items);
71	  const itemsTotal = regularItemsPremium(items) + componentsPremium(items);
72	  const policyModifier = policyBasePremium(items) * policyWideModifierRate(customer, quoteIndex);
73	  return Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
74	};
75	
76	const INSURANCE_VALUES: Record<string, number> = {
77	  sword: 1000,
78	  amulet: 600,
79	  staff: 800,
80	  potion: 400,
81	  rune: 250,
82	  moonstone: 250,
83	};
84	
85	const DEDUCTIBLE = 100;
86	const CAP_MULTIPLIER = 2;
87	
88	const reimbursableAmount = (damage: any, policyItems: any[]): number => {
89	  const item = policyItems.find((i: any) => i.type === damage.type);
90	  if (!item) {
91	    throw new Error(`Damage to item not covered by policy: ${damage.type}`);
92	  }
93	  const amount = item.enchantment >= 8 ? damage.amount * 0.5 : damage.amount;
94	  return Math.max(0, amount - DEDUCTIBLE);
95	};
96	
97	const insuranceSum = (policyItems: any[]): number =>
98	  policyItems.reduce((sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
99	
100	const calculateClaimPayout = (damages: any[], policyItems: any[], remainingCap: number): number =>
101	  Math.min(
102	    damages.reduce((sum: number, d: any) => sum + reimbursableAmount(d, policyItems), 0),
103	    remainingCap,
104	  );
105	
106	export const processScenario = (scenario: any): any => {
107	  const policies: any[][] = [];
108	  const remainingCaps: number[] = [];
109	  const results = scenario.steps.map((step: any) => {
110	    if (step.op === "claim") {
111	      const policyItems = policies[step.policyIndex];
112	      const payout = calculateClaimPayout(step.damages, policyItems, remainingCaps[step.policyIndex]);
113	      remainingCaps[step.policyIndex] -= payout;
114	      return { payout };
115	    }
116	    const premium = calculateQuotePremium(step.items, scenario.customer, policies.length);
117	    policies.push(step.items);
118	    remainingCaps.push(CAP_MULTIPLIER * insuranceSum(step.items));
119	    return { premium };
120	  });
121	  return { results };
122	};
